mapper.select:
SELECT p.payment_seq ,p.pg_provider ,p.pg_order_id ,p.pg_transaction_id ,p.amount ,p.currency ,p.original_amount ,p.discount_code ,p.discount_amount ,p.settle_amount ,p.settle_currency ,p.payment_method ,p.card_company ,p.card_last4 ,p.status ,p.paid_at ,p.created_at ,p.cancelled_at ,p.refunded_amount ,COALESCE(rc.refund_count, 0) AS refund_count ,p.event_pricing_seq ,pr.price_type ,pr.price_name ,p.discount_code_seq ,dc.discount_code ,p.event_seq ,e.title AS event_title ,e.event_type ,p.participant_seq ,p.event_participant_seq ,COALESCE(p.payer_name, TRIM(CONCAT_WS(' ', pa.first_name, NULLIF(pa.middle_name, ''), pa.last_name)) ) AS payer_name ,COALESCE(p.payer_email, pa.email) AS payer_email ,COALESCE(p.payer_country, pa.country) AS payer_country FROM event.payments p LEFT JOIN event.events e ON e.event_seq = p.event_seq LEFT JOIN event.event_pricing pr ON pr.event_pricing_seq = p.event_pricing_seq AND pr.deleted_at IS NULL LEFT JOIN event.event_discount_codes dc ON dc.discount_code_seq = p.discount_code_seq AND dc.deleted_at IS NULL LEFT JOIN event.participants pa ON pa.participant_seq = p.participant_seq LEFT JOIN ( SELECT payment_seq, COUNT(*) AS refund_count FROM event.refunds GROUP BY payment_seq ) rc ON rc.payment_seq = p.payment_seq
AND (e.organization_seq = #{organizationSeq} OR e.organization_seq IS NULL AND p.event_seq IS NULL)
AND ( LOWER(p.pg_order_id) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(COALESCE(p.pg_transaction_id, '')) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(COALESCE(p.payer_name, '')) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(COALESCE(p.payer_email, '')) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(COALESCE(pa.email, '')) LIKE '%' || LOWER(#{keyword}) || '%' )
AND p.event_seq IN
#{eventSeq}
AND p.status IN
#{status}
AND p.pg_provider IN
#{provider}
AND p.payment_method IN
#{method}
AND p.currency IN
#{currency}
AND COALESCE(p.paid_at, p.created_at) >= #{fromDate}
AND COALESCE(p.paid_at, p.created_at) < #{toDate}
AND p.amount >= #{minAmount}
AND p.amount <= #{maxAmount}
ORDER BY COALESCE(p.paid_at, p.created_at) DESC, p.payment_seq DESC

SELECT DISTINCT e.event_seq ,e.title ,e.event_type ,e.start_at FROM event.events e INNER JOIN event.payments p ON p.event_seq = e.event_seq WHERE e.deleted_at IS NULL
AND e.organization_seq = #{organizationSeq}
ORDER BY e.start_at DESC NULLS LAST, e.event_seq DESC

mapper.update:
UPDATE event.payments
SET status          = #{status}
   ,refunded_amount = #{refundedAmount}
   ,cancelled_at    = COALESCE(cancelled_at, #{cancelledAt})
   ,cancel_reason   = COALESCE(cancel_reason, #{cancelReason})
   ,updated_by      = #{updatedBy}
   ,updated_at      = now()
WHERE payment_seq   = #{paymentSeq}

UPDATE event.payments
SET admin_memo = #{adminMemo}
   ,updated_by = #{updatedBy}
   ,updated_at = now()
WHERE payment_seq = #{paymentSeq}
